struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // packet_id as plain uint32_t
        stream.serialise(packet_id);

        // username with length prefix
        // (Hexi’s serialise for std::string typically does this)
        stream.serialise(username);

        // scores: write count first, then the elements via operator<<
        uint32_t count = static_cast<uint32_t>(scores.size());
        stream.serialise(count);
        stream << scores;  // uses write_container internally

        // metadata as null-terminated string via adaptor
        stream.serialise(hexi::null_terminated(metadata));
    }
};

