    // Use Hexi’s writer with a dynamic byte buffer
    hexi::byte_vector buffer;
    hexi::writer writer{buffer};

    // Delegate to NetworkPacket::serialise
    const_cast<NetworkPacket&>(packet).serialise(writer);

    // Convert Hexi’s byte_vector to std::vector<uint8_t>
    return std::vector<uint8_t>(buffer.begin(), buffer.end());
