```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::deserializer d{buffer};

    NetworkPacket pkt{};

    // 1. Read packet_id
    d.read(pkt.packet_id);

    // 2. Read username using the length prefix
    //    Assume the username is encoded as: <uint32 length><bytes...>
    d.read(hexi::prefixed(pkt.username));

    // 3. Read score count, then use read_container to read the scores vector
    uint32_t score_count = 0;
    d.read(score_count);
    pkt.scores.resize(score_count);
    d.read_container(pkt.scores);

    // 4. Read the metadata string as null-terminated for zero-copy
    //    Use a string_view to get a zero-copy view, then copy into std::string.
    std::string_view metadata_view{};
    d.read(hexi::null_terminated(metadata_view));
    pkt.metadata.assign(metadata_view.begin(), metadata_view.end());

    // 5. Skip any remaining padding bytes (if any)
    if (auto remaining = d.remaining(); remaining > 0) {
        d.skip(remaining);
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::deserializer d{buffer};
    PacketInfo info{};

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    std::span<const uint8_t> id_span = d.span(sizeof(uint32_t));
    // Interpret the first 4 bytes as uint32_t
    info.packet_id = hexi::endian::little_to_native(
        *reinterpret_cast<const uint32_t*>(id_span.data())
    );

    // 2. Read username using prefixed adaptor to get a string_view
    //    This reads: <uint32 length><bytes...> as a view into the buffer.
    d.read(hexi::prefixed(info.username));

    // 3. Skip the scores vector without reading its elements:
    //    first read the count, then skip count * sizeof(uint32_t) bytes
    uint32_t score_count = 0;
    d.read(score_count);
    std::size_t bytes_to_skip = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    if (bytes_to_skip > d.remaining()) {
        // Not enough data; clamp to remaining to avoid UB
        bytes_to_skip = d.remaining();
    }
    d.skip(bytes_to_skip);

    return info;
}
