    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a Hexi reader over the given buffer
    hexi::reader r{buffer};

    // Get a zero-copy span over the header bytes
    auto header_span = r.span(sizeof(PacketHeader));

    // Interpret the span as a PacketHeader without copying
