#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};
    result.data_type = 0;

    // Create a buffer adaptor over the input buffer
    hexi::buffer_adaptor adaptor{
        const_cast<uint8_t*>(buffer.data()), // buffer_adaptor works on non-const
        buffer.size()
    };

    // Wrap the adaptor in a binary_stream
    hexi::binary_stream stream{adaptor};

    // 1) Preview the first byte (data_type) without advancing the read pointer
    uint8_t preview_type = 0;
    {
        auto view = stream.view(); // non-advancing view
        if (view.remaining() < sizeof(uint8_t)) {
            // Not enough data even for the type
            return result;
        }
        // Peek the first byte directly from the view
        preview_type = *view.data();
    }

    result.data_type = preview_type;

    // 2) Check available data size: data_type (1) + item_count (4)
    if (stream.remaining() < sizeof(uint8_t) + sizeof(uint32_t)) {
        // Not enough data for header
        return result;
    }

    // 3) Now actually read the header (this advances the read pointer)
    uint8_t data_type = 0;
    uint32_t item_count = 0;

    stream.read(data_type);
    stream.read(item_count);

    // 4) Read the items based on the data type
    if (data_type == 0) {
        // Integers: item_count * sizeof(uint32_t)
        const std::size_t needed =
            static_cast<std::size_t>(item_count) * sizeof(uint32_t);
        if (stream.remaining() < needed) {
            // Not enough data; return what we have in result (no items)
            return result;
        }

        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value = 0;
            stream.read(value);
            result.int_items[i] = value;
        }
    } else if (data_type == 1) {
        // Floats: item_count * sizeof(float)
        const std::size_t needed =
            static_cast<std::size_t>(item_count) * sizeof(float);
        if (stream.remaining() < needed) {
            // Not enough data; return what we have in result (no items)
            return result;
        }

        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            float value = 0.0f;
            stream.read(value);
            result.float_items[i] = value;
        }
    } else {
        // Unknown data type; leave result with just the previewed type
        return result;
    }

    return result;
}
