    std::size_t available = adaptor.read_avail();

    // Ensure there is enough data for the header
    if (available < header_size) {
        throw std::runtime_error("Not enough data to read PacketHeader");
    }

    // Create a binary_stream over the adaptor
    binary_stream stream{adaptor};

    // Get a zero-copy view (span) of the raw header bytes
    std::span<const std::byte> header_bytes = stream.read_span(header_size);

    // Interpret the bytes as the PacketHeader fields without copying
    PacketHeader header{};

    const std::byte* p = header_bytes.data();

    auto read_u32 = [](const std::byte* src) {
        std::uint32_t v;
        std::memcpy(&v, src, sizeof(v));
        return v;
    };

    auto read_u16 = [](const std::byte* src) {
        std::uint16_t v;
        std::memcpy(&v, src, sizeof(v));
        return v;
    };

    header.magic   = read_u32(p);
    p += sizeof(std::uint32_t);
    header.version = read_u16(p);
    p += sizeof(std::uint16_t);
    header.flags   = read_u16(p);

