struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor over the provided span
    hexi::buffer_adaptor adaptor{buffer};

    // Create a binary_stream using the adaptor
    hexi::binary_stream stream{adaptor};

    // Read the header (uint32_t)
    uint32_t header = 0;
    stream.read(header);

    // Get a view into the remaining data
    auto remaining = stream.view();

    // Find the null terminator in the remaining bytes
    const char* start = reinterpret_cast<const char*>(remaining.data());
    const char* end = start;
    const char* limit = start + remaining.size();

    while (end < limit && *end != '\0') {
        ++end;
    }

    // Construct a string_view that includes everything up to (but not including) the null terminator
    std::string_view message{start, static_cast<std::size_t>(end - start)};

    return MessagePacket{header, message};
}
