template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    // Get the current read position and total readable bytes
    const std::size_t read_pos = buffer.read_position();
    const std::size_t readable  = buffer.size();

    // Do not read past available data
    const std::size_t to_read = std::min(bytes_to_peek, readable);

    std::vector<uint8_t> result;
    result.resize(to_read);

    // Copy without modifying the buffer (const access)
    buffer.read_some(result.data(), to_read, read_pos);

    return result;
}
