#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using value_type = std::uint32_t;

    // Create a block allocator that can hold element_count values.
    // block_allocator<T, N> typically manages N objects of type T in a pool.
    hexi::block_allocator<value_type, element_count> allocator;

    // Pointers to keep track of allocated blocks
    value_type* blocks[element_count] = {nullptr};

    std::cout << "=== Initial allocations ===\n";

    // Allocate all available blocks
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate(1);
        std::cout << "Allocated block[" << i << "] at " << static_cast<void*>(blocks[i]) << "\n";
    }

    std::cout << "\n=== Deallocate some blocks (observe free list push behavior) ===\n";

    // Deallocate in non-trivial order to demonstrate LIFO free list behavior
    // Deallocate last block
    allocator.deallocate(blocks[element_count - 1], 1);
    std::cout << "Deallocated block[" << (element_count - 1) << "] at "
              << static_cast<void*>(blocks[element_count - 1]) << "\n";

    // Deallocate middle block
    size_t mid = element_count / 2;
    allocator.deallocate(blocks[mid], 1);
    std::cout << "Deallocated block[" << mid << "] at "
              << static_cast<void*>(blocks[mid]) << "\n";

    // Deallocate first block
    allocator.deallocate(blocks[0], 1);
    std::cout << "Deallocated block[0] at " << static_cast<void*>(blocks[0]) << "\n";

    std::cout << "\nAt this point, internally, each deallocate() call has\n"
                 "pushed the freed block onto the head of the free list (LIFO).\n";

    std::cout << "\n=== Re-allocate to observe pop behavior ===\n";

    // Reallocate three blocks; these should come back in reverse order
    // of deallocation if the free list is LIFO (stack-like).
    value_type* r0 = allocator.allocate(1);
    std::cout << "Re-allocated r0 at " << static_cast<void*>(r0)
              << " (expected most recently freed: block[0])\n";

    value_type* r1 = allocator.allocate(1);
    std::cout << "Re-allocated r1 at " << static_cast<void*>(r1)
              << " (expected next: block[" << mid << "])\n";

    value_type* r2 = allocator.allocate(1);
    std::cout << "Re-allocated r2 at " << static_cast<void*>(r2)
              << " (expected next: block[" << (element_count - 1) << "])\n";

    std::cout << "\nIf the printed addresses for r0, r1, and r2 match the\n"
                 "addresses of block[0], block[mid], and block[element_count-1]\n"
                 "respectively (in that order), it demonstrates that:\n"
                 "  - deallocate() internally uses push() to add blocks to\n"
                 "    the head of the free list, and\n"
                 "  - allocate() internally uses pop() to remove from that head.\n";

    // Clean up: deallocate everything we currently own.
    // First deallocate the re-allocated ones:
    allocator.deallocate(r0, 1);
    allocator.deallocate(r1, 1);
    allocator.deallocate(r2, 1);

    // Then deallocate the remaining still-allocated original blocks:
    for (size_t i = 1; i < element_count - 1; ++i) {
        if (i == mid) {
            continue; // block[mid] was already freed and reused
        }
        allocator.deallocate(blocks[i], 1);
    }

    std::cout << "\n=== Done demonstrating block_allocator free list behavior ===\n";
}

// Optional: a small main() to run the demonstration if this file is built standalone.
int main() {
    demonstrate_block_allocator_behavior<10>();
    return 0;
}
```

