#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    // Convert value in-place from big-endian representation to native endianness.
    // If the platform is already big-endian, no change is needed.
    if constexpr (std::endian::native == std::endian::big) {
        // No conversion required.
    } else if constexpr (std::endian::native == std::endian::little) {
        // Stored as big-endian, but we are little-endian: byteswap in place.
        value = hexi::byteswap(value);
    } else {
        static_assert(std::endian::native == std::endian::little
                   || std::endian::native == std::endian::big,
                      "Unsupported mixed-endian architecture");
    }
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    // Convert value in-place from little-endian representation to native endianness.
    // If the platform is already little-endian, no change is needed.
    if constexpr (std::endian::native == std::endian::little) {
        // No conversion required.
    } else if constexpr (std::endian::native == std::endian::big) {
        // Stored as little-endian, but we are big-endian: byteswap in place.
        value = hexi::byteswap(value);
    } else {
        static_assert(std::endian::native == std::endian::little
                   || std::endian::native == std::endian::big,
                      "Unsupported mixed-endian architecture");
    }
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    // Convert value in-place from endianness `from` to endianness `to`.

    if constexpr (from == to) {
        // No conversion needed.
        return;
    } else {
        // Different endianness: byteswap the value in place.
        value = hexi::byteswap(value);
    }
}
