```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

// 1. Preview data without advancing the read pointer.
//
// Assumptions about Hexi intrusive_storage interface (common pattern):
//   - size_t readable_bytes() const;  // number of bytes available to read
//   - size_t peek(uint8_t* dst, size_t n) const;
//       * copies up to n bytes from the current read position
//         into dst without advancing the read offset
//
// If your actual Hexi version uses different names, you may need to
// adapt the function calls accordingly.
template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview)
{
    // Determine how many bytes we can actually preview
    const size_t available = storage.readable_bytes();
    const size_t to_copy   = std::min(available, bytes_to_preview);

    std::vector<uint8_t> result(to_copy);
    if (to_copy == 0) {
        return result;
    }

    // Non‑destructive read
    storage.peek(result.data(), to_copy);
    return result;
}

// 2. Buffer status information
template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size; // bytes that can be read
    size_t free_space;    // bytes that can still be written
};

// Specialization for the requested signature using block_size = 1024.
//
// Assumptions about intrusive_storage interface:
//   - size_t readable_bytes() const;
//   - size_t writable_bytes() const;  // remaining capacity
BufferStatus<> check_buffer_status(
    const hexi::detail::intrusive_storage<1024>& storage)
{
    BufferStatus<> status{};
    status.readable_size = storage.readable_bytes();
    status.free_space    = storage.writable_bytes();
    return status;
}

// 3. Reset both read and write offsets.
//
// Assumptions about intrusive_storage interface:
//   - void clear();  // drops all data, resets read/write positions
template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage)
{
    storage.clear();
}
