#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Open file with Hexi's file_buffer
    hexi::file_buffer file(file_path);

    // Determine how many bytes can actually be read
    const auto file_size = file.size();
    const auto bytes_to_read = static_cast<size_t>(
        std::min<std::uintmax_t>(file_size, static_cast<std::uintmax_t>(header_size))
    );

    std::vector<uint8_t> header(bytes_to_read);
    if (bytes_to_read == 0) {
        return header; // empty file or header_size == 0
    }

    // Save current read position
    const auto original_pos = file.tellg();

    // Read from the beginning without permanently advancing the read pointer
    file.seekg(0);
    file.read(reinterpret_cast<char*>(header.data()), bytes_to_read);

    // Restore original read position
    file.seekg(original_pos);

    return header;
}
