#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                          const std::vector<uint8_t>& data) {
    // Write as many bytes as will fit into the remaining capacity
    const std::size_t writable = std::min<std::size_t>(data.size(), buffer.free_size());

    for (std::size_t i = 0; i < writable; ++i) {
        buffer.push_back(static_cast<std::byte>(data[i]));
    }
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                                           size_t bytes_to_read) {
    // Read up to bytes_to_read, but not more than what is currently stored
    const std::size_t readable = std::min<std::size_t>(bytes_to_read, buffer.size());
    std::vector<uint8_t> result;
    result.reserve(readable);

    for (std::size_t i = 0; i < readable; ++i) {
        std::byte b = buffer.front();
        buffer.pop_front();
        result.push_back(static_cast<uint8_t>(b));
    }

    return result;
}
