#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(
    const hexi::static_buffer<std::byte, buffer_size>& buffer,
    size_t bytes_to_preview
) {
    // We assume Hexi's static_buffer provides:
    // - size(): number of readable bytes currently stored
    // - peek(std::byte* dst, size_t count): copies up to `count` bytes
    //   from the buffer into `dst` without advancing the read pointer.
    //
    // If the actual Hexi API differs, adapt the calls accordingly.

    // Clamp preview size to what is actually available in the buffer
    const size_t available = buffer.size();
    const size_t to_copy   = std::min(bytes_to_preview, available);

    std::vector<uint8_t> out;
    out.resize(to_copy);

    if (to_copy == 0) {
        return out; // empty preview
    }

    // Temporary storage in std::byte to match buffer's value_type
    std::vector<std::byte> temp(to_copy);

    // Non-destructive read (preview)
    buffer.peek(temp.data(), to_copy);

    // Convert std::byte -> uint8_t
    for (size_t i = 0; i < to_copy; ++i) {
        out[i] = static_cast<uint8_t>(temp[i]);
    }

    return out;
}
