#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer,
                               const std::vector<uint32_t>& container) {
    // Write the size of the container first
    uint32_t count = static_cast<uint32_t>(container.size());
    writer.write(count);

    // Then write the raw data if there is any
    if (!container.empty()) {
        writer.write(container.data(),
                     static_cast<uint32_t>(container.size() * sizeof(uint32_t)));
    }
