    // Read the number of elements
    uint32_t count = 0;
    reader.read(count);

    std::vector<uint32_t> container;
    container.resize(count);

    // Read the raw data if there is any
    if (count > 0) {
        reader.read(container.data(),
                    static_cast<uint32_t>(count * sizeof(uint32_t)));
