#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>   // for std::memcmp

// Copy 'length' bytes from the buffer into 'data' without advancing the read pointer.
void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           void* data,
                           std::size_t length) {
    // Save current read position
    auto const saved_pos = buffer.read_pos();

    // Use non-template copy() overload for raw bytes
    buffer.copy(static_cast<std::byte*>(data), length);

    // Restore read position so we don't consume data
    buffer.read_pos(saved_pos);
}

// Peek a single value of type T from the buffer without consuming it.
template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                            T& value) {
    auto const saved_pos = buffer.read_pos();

    // Use template copy() overload to copy a single value
    buffer.copy(value);

    buffer.read_pos(saved_pos);
}

// Peek 'length' bytes from the buffer and compare them with 'expected' without consuming.
bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                      const void* expected,
                      std::size_t length) {
    // Allocate temporary storage for peeked data
    std::vector<std::byte> tmp(length);

    auto const saved_pos = buffer.read_pos();

    // Copy without advancing (we'll restore position after)
    if (length != 0) {
        buffer.copy(tmp.data(), length);
    }

    buffer.read_pos(saved_pos);

    // Compare peeked bytes with expected
    return std::memcmp(tmp.data(), expected, length) == 0;
}
