#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>
#include <cstring>   // for std::memcpy
#include <type_traits>

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Query capability flags (if provided by Hexi) or do a small probe.
    //
    // Many Hexi adaptors expose can_read_seek / can_write_seek via traits or
    // member functions. If buffer_adaptor provides such a member, prefer that.
    // Otherwise, we try a non‑modifying probe (seek to current position).
    //
    // The following assumes a member function:
    //     bool can_write_seek() const;
    //
    // If your actual Hexi version exposes it differently (e.g. as a trait),
    // adjust accordingly.
    if constexpr (requires(const hexi::pmc::buffer_adaptor<std::vector<std::byte>>& b) {
                      { b.can_write_seek() } -> std::convertible_to<bool>;
                  }) {
        return buffer.can_write_seek();
    } else {
        // Fallback: attempt a no‑op seek and see if it succeeds.
        try {
            buffer.write_seek(hexi::buffer_seek::current, 0);
            return true;
        } catch (...) {
            return false;
        }
    }
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                         hexi::buffer_seek direction,
                         std::size_t offset) {
    // Use Hexi's write_seek with the provided direction and offset.
    //
    // Hexi typically defines buffer_seek as something like:
    //   enum class buffer_seek { begin, current, end };
    //
    // We simply forward the call; any range checking or error handling is
    // performed by Hexi.
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                               uint32_t header_value) {
    // General pattern:
    // 1. Remember the current write position.
    // 2. Seek to the beginning to write a placeholder header (or overwrite an
    //    existing one).
    // 3. Seek back to the saved position and write the body.
    // 4. At the end, seek back to the beginning to update the header.
    //
    // Since the body-writing logic is not specified by the caller, this
    // function demonstrates the mechanics of write seeking and header
    // rewriting, leaving the actual "body" content up to the caller in real
    // use. Here we show a minimal, self‑contained implementation.

    // Save current write position.
    std::size_t saved_pos = buffer.write_tell();

    // Seek to the beginning of the buffer to write the (initial) header.
    buffer.write_seek(hexi::buffer_seek::begin, 0);

    // Ensure there is enough space for the header in the underlying buffer.
    // 4 bytes for uint32_t.
    constexpr std::size_t header_size = sizeof(uint32_t);

    auto& underlying = buffer.buffer();  // Assuming buffer_adaptor exposes buffer()
    if (underlying.size() < header_size) {
        underlying.resize(header_size);
    }

    // Write an initial (placeholder) header, e.g., 0.
    {
        uint32_t placeholder = 0;
        std::byte bytes[header_size];
        std::memcpy(bytes, &placeholder, header_size);
        buffer.write(bytes, header_size);
    }

    // Seek back to the saved position to write the "body".
    buffer.write_seek(hexi::buffer_seek::begin, saved_pos);

    // ---- Body writing would happen here in real code ----
    // For demonstration, we append some dummy bytes so that the header_value
    // we later write at position 0 has some meaning (e.g., total size).
    {
        const char* dummy = "BODY";
        const std::size_t dummy_len = 4;
        std::byte bytes[dummy_len];
        std::memcpy(bytes, dummy, dummy_len);
        buffer.write(bytes, dummy_len);
    }
    // -----------------------------------------------------

    // Finally, seek back to the beginning and update the header with the
    // supplied header_value.
    buffer.write_seek(hexi::buffer_seek::begin, 0);

    {
        std::byte bytes[header_size];
        std::memcpy(bytes, &header_value, header_size);
        buffer.write(bytes, header_size);
    }

    // Optionally, seek back to the end (or the previously saved position) if
    // the caller expects the write cursor to be at a particular location.
    // Here we restore the position to where the body ends.
    buffer.write_seek(hexi::buffer_seek::end, 0);
}
