using namespace hexi::detail;

// Helper: zigzag encode for signed integers
template<typename T>
typename std::make_unsigned<T>::type zigzag_encode(T value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    // Shift left by 1 and xor with sign bit shifted to LSB
    return (static_cast<Unsigned>(value) << 1) ^
           static_cast<Unsigned>(value >> (sizeof(T) * 8 - 1));
}

// Helper: zigzag decode for signed integers
template<typename T>
T zigzag_decode(typename std::make_unsigned<T>::type value) {
    using Unsigned = typename std::make_unsigned<T>::type;
    Unsigned tmp = value;
    return static_cast<T>((tmp >> 1) ^ static_cast<Unsigned>(-(tmp & 1)));
}

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_integral<T>::value, "encode_varint requires integral type");

    using Unsigned = typename std::conditional<
        std::is_signed<T>::value,
        typename std::make_unsigned<T>::type,
        T
    >::type;

    Unsigned v;
    if constexpr (std::is_signed<T>::value) {
        v = zigzag_encode(value);
    } else {
        v = static_cast<Unsigned>(value);
    }

    std::size_t bytes_written = 0;
    while (true) {
        std::uint8_t byte = static_cast<std::uint8_t>(v & 0x7F);
        v >>= 7;
        if (v != 0) {
            byte |= 0x80; // continuation bit
        }
        writer.write(byte);
        ++bytes_written;
        if (v == 0) {
            break;
        }
    }
    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_integral<T>::value, "decode_varint requires integral type");

    using Unsigned = typename std::conditional<
        std::is_signed<T>::value,
        typename std::make_unsigned<T>::type,
        T
    >::type;

    Unsigned result = 0;
    int shift = 0;
    while (true) {
        std::uint8_t byte = 0;
        reader.read(byte);
        result |= (static_cast<Unsigned>(byte & 0x7F) << shift);
        if ((byte & 0x80) == 0) {
            break;
        }
        shift += 7;
    }

    if constexpr (std::is_signed<T>::value) {
        return zigzag_decode<T>(result);
    } else {
        return static_cast<T>(result);
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Adapt a std::vector<uint8_t> as a buffer for Hexi's stream classes
    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint(writer, original_value);

    // Prepare to decode from the same buffer
    hexi::pmc::binary_stream_reader reader(adaptor);
    T decoded = decode_varint<T>(reader);

    return decoded == original_value;
}
