```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Treat null pointers with non-zero length as invalid/overlapping for safety
    if ((!src && src_len != 0) || (!dst && dst_len != 0)) {
        return true;
    }

    // Zero-length regions never overlap
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    // Use Hexi's safe integer utilities to avoid overflow when computing end addresses
    auto src_begin = reinterpret_cast<const std::byte*>(src);
    auto dst_begin = reinterpret_cast<const std::byte*>(dst);

    // Compute src_end = src_begin + src_len, dst_end = dst_begin + dst_len safely
    std::byte const* src_end;
    std::byte const* dst_end;

    {
        std::byte const* tmp = nullptr;
        if (!checked_add(src_begin, src_len, tmp)) {
            // If overflow occurs, treat as overlapping for safety
            return true;
        }
        src_end = tmp;
    }

    {
        std::byte const* tmp = nullptr;
        if (!checked_add(dst_begin, dst_len, tmp)) {
            // If overflow occurs, treat as overlapping for safety
            return true;
        }
        dst_end = tmp;
    }

    // Two half-open intervals [src_begin, src_end) and [dst_begin, dst_end) overlap if:
    // src_begin < dst_end && dst_begin < src_end
    return (src_begin < dst_end) && (dst_begin < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Trivial success for zero-length copy
    if (length == 0) {
        return true;
    }

    // Basic pointer validation
    if (!destination || !source) {
        return false;
    }

    // If the regions overlap, do not perform the copy
    if (check_regions_overlap(source, length, destination, length)) {
        return false;
    }

    // At this point, regions are non-overlapping, so memcpy is safe
    std::memcpy(destination, source, length);
    return true;
}
