```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a backing buffer; in a realistic scenario you might choose
    // some capacity policy, here we just size it to input_data.size().
    std::vector<uint8_t> backing_buffer(input_data.size());

    // Create a write adaptor over the backing buffer
    hexi::pmc::buffer_write_adaptor writer(backing_buffer.data(),
                                           backing_buffer.size());

    // Write as much of input_data as fits in the writer's free space
    std::size_t to_write = std::min<std::size_t>(input_data.size(), writer.free());
    std::size_t written  = writer.write(input_data.data(), to_write);

    // Now create a read adaptor over the same backing buffer
    hexi::pmc::buffer_read_adaptor reader(backing_buffer.data(),
                                          backing_buffer.size());

    // We should only attempt to read as much as was actually written
    std::size_t readable = std::min<std::size_t>(reader.size(), written);

    std::vector<uint8_t> output(readable);
    if (readable > 0) {
        std::size_t read_bytes = reader.read(output.data(), readable);
        output.resize(read_bytes); // in case read() returns less than requested
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data,
                                                 std::size_t peek_size) {
    // Create a read adaptor over the provided buffer_data
    hexi::pmc::buffer_read_adaptor reader(buffer_data.data(),
                                          buffer_data.size());

    // Determine how many bytes we can safely peek
    std::size_t available = reader.size();
    std::size_t to_peek   = std::min<std::size_t>(available, peek_size);

    // Use copy() to peek without advancing the internal read cursor
    std::vector<uint8_t> peeked(to_peek);
    if (to_peek > 0) {
        // copy() reads from current read position but does not advance it
        reader.copy(peeked.data(), to_peek);
    }

    // Demonstrate use of read_ptr(): get a pointer to the current read position
    const uint8_t* current_read_ptr = static_cast<const uint8_t*>(reader.read_ptr());
    (void)current_read_ptr; // suppress unused-variable warning if not otherwise used

    // Now actually consume the data we peeked at using read()
    if (to_peek > 0) {
        // This will advance the read cursor by to_peek bytes
        std::vector<uint8_t> consumed(to_peek);
        reader.read(consumed.data(), to_peek);
        // We return the data that we peeked (and then consumed)
        return consumed;
    }

    // Nothing to peek/consume
    return {};
}
```

