#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Initialize a buffer large enough to hold all chunks
    std::size_t total_input_size = 0;
    for (const auto& c : chunks) {
        total_input_size += c.size();
    }

    // Allocate backing storage
    std::vector<uint8_t> storage(total_input_size, 0);

    // Create Hexi write adaptor on top of this storage
    hexi::pmc::buffer_write_adaptor writer(storage.data(), storage.size());

    // Write each chunk separately, checking free() before each write
    for (const auto& chunk : chunks) {
        std::size_t remaining = writer.free();
        if (remaining == 0) {
            break; // no more space
        }

        const std::size_t to_write = std::min(remaining, chunk.size());
        if (to_write == 0) {
            continue;
        }

        writer.write(chunk.data(), to_write);

        // If the chunk did not fully fit, stop writing further chunks
        if (to_write < chunk.size()) {
            break;
        }
    }

    // The final buffer size is the number of bytes actually written
    return writer.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Prepare a read adaptor over the input buffer
    hexi::pmc::buffer_read_adaptor reader(buffer.data(), buffer.size());

    std::vector<uint8_t> result;
    result.reserve(buffer.size());

    // Read until the adaptor reports no more data
    while (reader.size() > 0) {
        std::size_t available = reader.size();
        std::size_t to_read = std::min(available, chunk_size);

        std::vector<uint8_t> tmp(to_read);
        reader.read(tmp.data(), to_read);

        // Append the partially read data to result
        result.insert(result.end(), tmp.begin(), tmp.end());
    }

    return result;
}
