    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    using hexi::pmc::buffer_read_adaptor;

    // Create an adaptor over the input buffer
    buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    // We expect to peek a fixed-size header
    Header hdr{};
    const std::size_t header_size = sizeof(Header);

    if (buffer.size() < header_size) {
        throw std::runtime_error("Buffer too small for header");
    }

    // Use copy() to peek header bytes without advancing the read cursor.
    // copy(dst, n) copies from the current read position but does not consume.
