#include <hexi/hexi.h>
#include <hexi/endian.h>

#include <vector>
#include <cstdint>
#include <string>
#include <string_view>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialisation (const) – write to stream
    void serialise(auto& adaptor) const {
        using hexi::conditional_reverse;
        using std::endian;

        // Write sensor_id directly in native endianness
        adaptor.write(sensor_id);

        // Write temperatures:
        //   - write count (so we know how many to read later)
        //   - then each temperature converted to little-endian
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(count);

        for (float t : temperatures) {
            float le_t = conditional_reverse(t, endian::native, endian::little);
            adaptor.write(le_t);
        }

        // Write pressure converted to little-endian
        double le_p = conditional_reverse(pressure, endian::native, endian::little);
        adaptor.write(le_p);
    }

    // Deserialisation (non-const) – read from stream
    void serialise(auto& adaptor) {
        using hexi::little_to_native_inplace;

        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read count, then that many temperatures
        uint32_t count = 0;
        adaptor.read(count);
        temperatures.resize(count);

        for (uint32_t i = 0; i < count; ++i) {
            adaptor.read(temperatures[i]);               // in little-endian
            little_to_native_inplace(temperatures[i]);   // convert to native in-place
        }

        adaptor.read(pressure);                          // in little-endian
        little_to_native_inplace(pressure);              // convert to native in-place
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    using hexi::OutputMemoryStream;

    // Create an output stream over a dynamic buffer
    OutputMemoryStream stream;
    // Serialise the entire structure via the adaptor's serialise method
    stream.serialise(data);

    // Extract the underlying buffer
    const auto& buf = stream.buffer();
    return std::vector<uint8_t>(buf.begin(), buf.end());
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    using hexi::InputMemoryStream;

    MeasurementData result;

    // Create an input stream over the provided buffer
    InputMemoryStream stream(buffer.data(), buffer.size());
    // Deserialise the entire structure
    stream.deserialise(result);

    return result;
}

